reg [1:0] next_state;
//parameter STATE_0=2'b00,STATE_1=2'b01, STATE_2=2'b10;


always @( current_state)
	begin
		case(current_state)
			2'b00: result <= 1'b0;
			2'b01: result  <= 1'b1;
			default: result  <= 1'b0;
		endcase
	end

always @(posedge clk or negedge rst)
	begin
		if(rst==1'b0)
			current_state <= 2'b00;
		else
			current_state  <= next_state;
	end

always @ (current_state or condition)
	begin
		case(current_state)
