案例代码: 
module fd31(
	input wire a_1,
	input wire b_1,
	input wire sl_1,
	output reg q_1 
);

always@(a_1 or b_1)         //当敏感信号不完整时，综合前后的网表仿真可能会不一致在组合逻辑块中，
							//敏感信号列表一定要包含这个过程或块读入的每个信号；对于时序逻辑，敏感信号列表一定要包含时钟和其他异步控制信号。
						    //另外，也要避免敏感信号列表中出现不必要的信号
	begin
		if(!sl) 
			q_1 = a_1;
		else    
			q_1 = b_1;
	end 
endmodule

案例代码:
module fd31(
	input wire  a_1,
	input wire  b_1,
	input wire  sl_1,
	output reg  q_1 
);
parameter p_1 = 1'b1;

always@(sl_1 or a_1 or b_1 or p_1)     //always的敏感信号列表中不能出现常量
	begin
		if(!sl) q_1 = a_1;
		else q_1 = b_1 & p_1;
	end 
endmodule

