	//违反

		module fd11(
		input wire d_1,
		input wire clk_2,
		input wire clr,
		output reg q_1 
	);

		reg in_2,in_3,in_4;

		always@(posedge clk_2)
		begin
			if(clr)
				begin
				in_2 <=  1'b0;
				in_3 <=  1'b0;
				q_1 <=1'b0;
				end	 
			else
				begin
					in_2 <=   d_1;	
					in_3 <=  in_2;
					q_1 <=  in_3; 
				end	

		end 

		endmodule

